+    auto response = future.get();
+    if (response->id != "ros1") {
+      throw std::runtime_error("Expected a response from ROS1");
+    }
+  } else {
+    throw std::runtime_error("Failed to call service ros1_bridge_test");
+  }
+
+  rclcpp::shutdown();
+  return 0;
